142   <div class="toolbar">
143     <label for="sort">Sort by</label>
144     <select id="sort">
145       <option value="priority">Priority</option>
146       <option value="newest">Newest</option>
147       <option value="oldest">Oldest</option>
148       <option value="alpha">A–Z</option>
