156 <script>
157   const listEl = document.getElementById("list");
158   const countEl = document.getElementById("count");
159   const form = document.getElementById("add-form");
160   const input = document.getElementById("add-input");
161   const sortEl = document.getElementById("sort");
162 
163   // The latest list as received from the server, before applying the chosen
164   // sort. Kept so editing can recover a task's raw (un-linkified) text.
165   let allTodos = [];
166 
167   function escapeHtml(s) {
168     return s.replace(/[&<>"']/g, c => (
169       { "&": "&amp;", "<": "&lt;", ">": "&gt;", '"': "&quot;", "'": "&#39;" }[c]
170     ));
171   }
172 
173   // Escape text, then turn any http(s) URLs into clickable links.
174   function linkify(s) {
175     const urlRe = /(https?:\/\/[^\s<]+)/g;
176     let out = "", last = 0, m;
177     while ((m = urlRe.exec(s)) !== null) {
178       out += escapeHtml(s.slice(last, m.index));
179       const url = m[0];
180       out += `<a href="${escapeHtml(url)}" target="_blank" rel="noopener noreferrer">${escapeHtml(url)}</a>`;
181       last = m.index + url.length;
182     }
183     out += escapeHtml(s.slice(last));
184     return out;
185   }
186 
187   const PRIO_RANK = { high: 2, medium: 1, low: 0 };
188 
189   function sortTodos(todos) {
190     const t = todos.slice();
191     switch (sortEl.value) {
192       case "newest": return t.sort((a, b) => b.id - a.id);
193       case "oldest": return t.sort((a, b) => a.id - b.id);
194       case "alpha":  return t.sort((a, b) => a.text.localeCompare(b.text));
195       case "priority":
196       default:
197         return t.sort((a, b) =>
198           (PRIO_RANK[b.priority] ?? 1) - (PRIO_RANK[a.priority] ?? 1) || b.id - a.id);
199     }
200   }
201 
202   function render() {
203     const todos = sortTodos(allTodos);
204     const open = todos.filter(t => !t.done).length;
205     countEl.textContent = todos.length
206       ? `${open} open · ${todos.length} total`
207       : "";
208 
209     if (!todos.length) {
210       listEl.innerHTML = '<div class="empty">Nothing to do. Add a task above. 🎉</div>';
211       return;
212     }
213 
214     listEl.innerHTML = todos.map(t => {
215       const prio = t.priority || "medium";
216       const opt = (v, label) =>
217         `<option value="${v}" ${prio === v ? "selected" : ""}>${label}</option>`;
218       return `
219       <li class="item prio-${prio} ${t.done ? "done" : ""}" data-id="${t.id}">
220         <button class="check" data-action="toggle" title="Toggle complete">✓</button>
221         <span class="text" title="Double-click to edit">${linkify(t.text)}</span>
222         <button class="edit" data-action="edit" title="Edit">✎</button>
223         <select class="prio" data-action="priority" title="Priority">
224           ${opt("high", "High")}${opt("medium", "Medium")}${opt("low", "Low")}
225         </select>
226         <button class="ship" data-action="ship" title="Send this task to the AI daemon">🚀 AI</button>
227         <button class="del" data-action="delete" title="Remove">×</button>
228       </li>
229     `;
230     }).join("");
231   }
232 
233   async function api(path, body) {
234     const opts = body
235       ? { method: "POST", headers: { "Content-Type": "application/json" }, body: JSON.stringify(body) }
236       : {};
237     const res = await fetch(path, opts);
238     if (!res.ok) throw new Error(await res.text());
239     return res.json();
240   }
241 
242   function setTodos(todos) {
243     allTodos = todos;
244     render();
245   }
246 
247   async function refresh() {
248     setTodos(await api("/api/todos"));
249   }
250 
251   // Swap a task's text for an inline input, saving on Enter/blur and
252   // cancelling on Escape.
253   function startEdit(id) {
254     const li = listEl.querySelector(`.item[data-id="${id}"]`);
255     const todo = allTodos.find(t => t.id === id);
256     if (!li || !todo) return;
257     const textEl = li.querySelector(".text");
258 
259     const inp = document.createElement("input");
260     inp.className = "edit-input";
261     inp.value = todo.text;
262     textEl.replaceWith(inp);
263     inp.focus();
264     inp.setSelectionRange(inp.value.length, inp.value.length);
265 
266     let settled = false;
267     const commit = async (save) => {
268       if (settled) return;
269       settled = true;
270       const val = inp.value.trim();
271       if (save && val && val !== todo.text) {
272         setTodos(await api("/api/todos/edit", { id, text: val }));
273       } else {
274         render();
275       }
276     };
277 
278     inp.addEventListener("keydown", (e) => {
279       if (e.key === "Enter") { e.preventDefault(); commit(true); }
280       else if (e.key === "Escape") { e.preventDefault(); commit(false); }
281     });
282     inp.addEventListener("blur", () => commit(true));
283   }
284 
285   form.addEventListener("submit", async (e) => {
286     e.preventDefault();
287     const text = input.value.trim();
288     if (!text) return;
289     setTodos(await api("/api/todos", { text }));
290     input.value = "";
291     input.focus();
292   });
293 
294   sortEl.addEventListener("change", render);
295 
296   listEl.addEventListener("click", async (e) => {
297     const btn = e.target.closest("button[data-action]");
298     if (!btn) return;
299     const id = Number(btn.closest(".item").dataset.id);
300     const action = btn.dataset.action;
301     if (action === "edit") { startEdit(id); return; }
302     if (action === "ship") { shipToAi(id, btn); return; }
303     setTodos(await api(`/api/todos/${action}`, { id }));
304   });
305 
306   // Hand a task to the ciabatta ai daemon (proxied through the todo server, so
307   // there's no cross-origin call from the browser).
308   async function shipToAi(id, btn) {
309     btn.disabled = true;
310     const original = btn.textContent;
311     btn.textContent = "shipping…";
312     try {
313       const res = await fetch("/api/ship", {
314         method: "POST",
315         headers: { "Content-Type": "application/json" },
316         body: JSON.stringify({ id }),
317       });
318       if (res.ok) {
319         const data = await res.json().catch(() => ({}));
320         const jobId = data.job && data.job.id;
321         toast(jobId ? `Shipped to AI — job #${jobId} running` : "Shipped to the AI");
322       } else {
323         toast(`Couldn't ship: ${await res.text()}`);
324       }
325     } catch {
326       toast("Couldn't reach the todo server");
327     } finally {
328       btn.disabled = false;
329       btn.textContent = original;
330     }
331   }
332 
333   let toastTimer;
334   function toast(msg) {
335     const t = document.getElementById("toast");
336     t.textContent = msg;
337     t.classList.add("show");
338     clearTimeout(toastTimer);
339     toastTimer = setTimeout(() => t.classList.remove("show"), 2600);
340   }
341 
342   // Poll whether the ai daemon is up; the ship buttons only show when it is.
343   async function pollAiStatus() {
344     const textEl = document.getElementById("ai-pill-text");
345     try {
346       const s = await (await fetch("/api/ai-status")).json();
347       const on = !!s.running;
348       document.body.classList.toggle("ai-on", on);
349       textEl.textContent = on
350         ? `AI daemon: connected (:${s.port})`
351         : "AI daemon: not running";
352     } catch {
353       document.body.classList.remove("ai-on");
354       textEl.textContent = "AI daemon: unknown";
355     } finally {
356       setTimeout(pollAiStatus, 4000);
357     }
358   }
359 
360   listEl.addEventListener("dblclick", (e) => {
361     const textEl = e.target.closest(".text");
362     if (!textEl || e.target.closest("a")) return;
363     startEdit(Number(textEl.closest(".item").dataset.id));
364   });
365 
366   listEl.addEventListener("change", async (e) => {
367     const sel = e.target.closest("select[data-action='priority']");
368     if (!sel) return;
369     const id = Number(sel.closest(".item").dataset.id);
370     setTodos(await api("/api/todos/priority", { id, priority: sel.value }));
371   });
372 
373   refresh();
374   pollAiStatus();
375 </script>
376 </body>
377 </html>

