  1 //! A tiny, dependency-free HTTP server for the todo web app.
  2 //!
  3 //! It serves the embedded single-page UI at `/` and a small JSON API under
  4 //! `/api/todos` (list / add / toggle / delete). Every mutating request returns
  5 //! the full, updated list so the front end can simply re-render.
  6 //!
  7 //! It also bridges to the `ciabatta ai` daemon: `/api/ai-status` reports
  8 //! whether that daemon is reachable, and `/api/ship` forwards a todo to it as a
  9 //! background task. The forwarding happens here (server-side) so the browser
 10 //! never makes a cross-origin request to the AI daemon.
 11 
 12 use std::sync::Arc;
 13 
 14 use anyhow::Result;
 15 use serde::Deserialize;
 16 use serde_json::json;
 17 use tokio::io::{AsyncReadExt, AsyncWriteExt};
 18 use tokio::net::{TcpListener, TcpStream};
 19 
 20 use super::{Priority, Store};
 21 
 22 /// The embedded single-page app (HTML + CSS + JS, no external assets).
 23 const INDEX_HTML: &str = include_str!("index.html");
 24 
 25 /// Serve the todo app on `127.0.0.1:port` until the process is interrupted.
 26 /// `ai_port` is where the `ciabatta ai` daemon is expected to be listening, so
 27 /// the app can offer to ship tasks to it.
 28 pub async fn serve(store: Arc<Store>, port: u16, ai_port: u16) -> Result<()> {
 29     let host = crate::config::bind_host();
 30     let listener = TcpListener::bind((host.as_str(), port)).await.map_err(|e| {
 31         anyhow::anyhow!("Failed to bind {host}:{port} ({e}). Try a different --port.")
 32     })?;
 33 
 34     println!("\nTodo app ready at http://{host}:{port}");
 35     println!("Ship-to-AI targets the ciabatta ai daemon on port {ai_port}.");
 36     println!("Press Ctrl-C to stop.");
 37 
 38     loop {
 39         let (socket, _) = listener.accept().await?;
 40         let store = store.clone();
 41         tokio::spawn(async move {
 42             if let Err(e) = handle(socket, &store, ai_port).await {
 43                 eprintln!("todo server: connection error: {e}");
 44             }
 45         });
 46     }
 47 }
 48 
 49 /// Parsed pieces of a request we care about: method, path, and body.
 50 struct Request {
 51     method: String,
 52     path: String,
 53     body: String,
 54 }
 55 
 56 /// A JSON payload carrying just an id (toggle / delete).
 57 #[derive(Deserialize)]
 58 struct IdPayload {
 59     id: u64,
 60 }
 61 
 62 /// A JSON payload carrying task text (add).
 63 #[derive(Deserialize)]
 64 struct TextPayload {
 65     text: String,
 66 }
 67 
 68 /// A JSON payload setting a task's priority.
 69 #[derive(Deserialize)]
 70 struct PriorityPayload {
 71     id: u64,
 72     priority: Priority,
 73 }
 74 
 75 /// A JSON payload replacing a task's text (edit).
 76 #[derive(Deserialize)]
 77 struct EditPayload {
 78     id: u64,
 79     text: String,
 80 }
 81 
 82 async fn handle(mut socket: TcpStream, store: &Store, ai_port: u16) -> Result<()> {
 83     let Some(req) = read_request(&mut socket).await? else {
 84         return Ok(());
 85     };
 86 
 87     let (status, content_type, body): (&str, &str, Vec<u8>) =
 88         match (req.method.as_str(), req.path.as_str()) {
 89             ("GET", "/") | ("GET", "/index.html") => {
 90                 ("200 OK", "text/html; charset=utf-8", INDEX_HTML.into())
 91             }
 92             ("GET", "/api/ai-status") => {
 93                 let running = ai_daemon_reachable(ai_port).await;
 94                 ok_json(json!({ "running": running, "port": ai_port }))
 95             }
 96             ("POST", "/api/ship") => ship_to_ai(store, &req.body, ai_port).await,
 97             ("GET", "/api/todos") => json_response(store),
 98             ("POST", "/api/todos") => match serde_json::from_str::<TextPayload>(&req.body) {
 99                 Ok(p) => match store.add(&p.text) {
100                     Ok(_) => json_response(store),
101                     Err(e) => bad_request(&e.to_string()),
102                 },
103                 Err(e) => bad_request(&e.to_string()),
104             },
105             ("POST", "/api/todos/toggle") => mutate(store, &req.body, |s, id| s.toggle(id)),
106             ("POST", "/api/todos/delete") => mutate(store, &req.body, |s, id| s.remove(id)),
107             ("POST", "/api/todos/priority") => {
108                 match serde_json::from_str::<PriorityPayload>(&req.body) {
109                     Ok(p) => match store.set_priority(p.id, p.priority) {
110                         Ok(()) => json_response(store),
111                         Err(e) => bad_request(&e.to_string()),
112                     },
113                     Err(e) => bad_request(&e.to_string()),
114                 }
115             }
116             ("POST", "/api/todos/edit") => match serde_json::from_str::<EditPayload>(&req.body) {
117                 Ok(p) => match store.set_text(p.id, &p.text) {
118                     Ok(()) => json_response(store),
119                     Err(e) => bad_request(&e.to_string()),
120                 },
121                 Err(e) => bad_request(&e.to_string()),
122             },
123             _ => (
124                 "404 Not Found",
125                 "text/plain; charset=utf-8",
126                 b"not found".to_vec(),
127             ),
128         };
129 
130     write_response(&mut socket, status, content_type, &body).await
131 }
