159 /// Best-effort probe of the `ciabatta ai` daemon: it answers `GET /api/jobs`
160 /// only when it is up, so a quick, short-timeout request tells us if the
161 /// ship-to-AI button should be offered.
162 async fn ai_daemon_reachable(ai_port: u16) -> bool {
163     let Ok(client) = reqwest::Client::builder()
164         .timeout(std::time::Duration::from_millis(400))
165         .build()
166     else {
167         return false;
168     };
169     client
170         .get(format!("http://127.0.0.1:{ai_port}/api/jobs"))
171         .send()
172         .await
173         .map(|r| r.status().is_success())
174         .unwrap_or(false)
175 }
