177 /// Forward a todo to the AI daemon as a background task. The browser posts
178 /// `{"id": <todo id>}`; we resolve the task text here and hand it to the
179 /// daemon's `/api/ship`, tagging the source as `todo:<id>`.
180 async fn ship_to_ai(
181     store: &Store,
182     body: &str,
183     ai_port: u16,
184 ) -> (&'static str, &'static str, Vec<u8>) {
185     let id = match serde_json::from_str::<IdPayload>(body) {
186         Ok(p) => p.id,
187         Err(e) => return bad_request(&e.to_string()),
188     };
189     let Some(text) = store.text_of(id) else {
190         return bad_request(&format!("no todo #{id}"));
191     };
192 
193     let client = match reqwest::Client::builder()
194         .timeout(std::time::Duration::from_secs(5))
195         .build()
196     {
197         Ok(c) => c,
198         Err(e) => return bad_request(&e.to_string()),
199     };
200     let resp = client
201         .post(format!("http://127.0.0.1:{ai_port}/api/ship"))
202         .json(&json!({ "prompt": text, "source": format!("todo:{id}") }))
203         .send()
204         .await;
205 
206     match resp {
207         Ok(r) if r.status().is_success() => {
208             let job = r.json::<serde_json::Value>().await.unwrap_or_else(|_| json!({}));
209             ok_json(json!({ "ok": true, "job": job }))
210         }
211         Ok(r) => {
212             let code = r.status();
213             let msg = r.text().await.unwrap_or_default();
214             bad_request(&format!("AI daemon returned {code}: {msg}"))
215         }
216         Err(_) => bad_request(
217             "The ciabatta ai daemon isn't reachable. Start it with `ciabatta ai` \
218              in your project, then try again.",
219         ),
220     }
221 }
