232 /// Read a full HTTP request: the head, then any body indicated by
233 /// `Content-Length`. Returns `None` on an empty/closed connection.
234 async fn read_request(socket: &mut TcpStream) -> Result<Option<Request>> {
235     let mut buf = Vec::with_capacity(2048);
236     let mut chunk = [0u8; 2048];
237 
238     // Read until we've seen the end of the headers (a blank line).
239     let header_end = loop {
240         let n = socket.read(&mut chunk).await?;
241         if n == 0 {
242             if buf.is_empty() {
243                 return Ok(None);
244             }
245             break None;
246         }
247         buf.extend_from_slice(&chunk[..n]);
248         if let Some(pos) = find_subsequence(&buf, b"\r\n\r\n") {
249             break Some(pos + 4);
250         }
251     };
252 
253     let head_len = header_end.unwrap_or(buf.len());
254     let head = String::from_utf8_lossy(&buf[..head_len]).to_string();
255 
256     let mut lines = head.lines();
257     let request_line = lines.next().unwrap_or_default();
258     let mut parts = request_line.split_whitespace();
259     let method = parts.next().unwrap_or("GET").to_string();
260     let path = parts.next().unwrap_or("/").to_string();
261 
262     // Pull the body length from the headers, then read the rest of the body.
263     let content_length = lines
264         .take_while(|l| !l.is_empty())
265         .find_map(|l| {
266             let (name, value) = l.split_once(':')?;
267             name.trim()
268                 .eq_ignore_ascii_case("content-length")
269                 .then(|| value.trim().parse::<usize>().ok())
270                 .flatten()
271         })
272         .unwrap_or(0);
273 
274     let mut body_bytes = buf[head_len..].to_vec();
275     while body_bytes.len() < content_length {
276         let n = socket.read(&mut chunk).await?;
277         if n == 0 {
278             break;
279         }
280         body_bytes.extend_from_slice(&chunk[..n]);
281     }
282     let body = String::from_utf8_lossy(&body_bytes).to_string();
283 
284     Ok(Some(Request { method, path, body }))
285 }
286 
287 /// Byte-level substring search (for locating the header/body boundary).
288 fn find_subsequence(haystack: &[u8], needle: &[u8]) -> Option<usize> {
289     haystack
290         .windows(needle.len())
291         .position(|window| window == needle)
292 }
