294 /// Write a complete HTTP/1.1 response and close the connection.
295 async fn write_response(
296     socket: &mut TcpStream,
297     status: &str,
298     content_type: &str,
299     body: &[u8],
300 ) -> Result<()> {
301     let header = format!(
302         "HTTP/1.1 {status}\r\n\
303          Content-Type: {content_type}\r\n\
304          Content-Length: {}\r\n\
305          Cache-Control: no-store\r\n\
306          Connection: close\r\n\r\n",
307         body.len()
308     );
309     socket.write_all(header.as_bytes()).await?;
310     socket.write_all(body).await?;
311     socket.flush().await?;
312     Ok(())
313 }
